use async_trait::async_trait;
use std::time::Duration;

#[async_trait]
pub trait CacheBackend: Send + Sync {
    type Error;

    async fn get(&self, key: &str) -> Result<Option<Vec<u8>>, Self::Error>;
    async fn set(&self, key: &str, value: &[u8], ttl: Option<Duration>) -> Result<(), Self::Error>;
    async fn delete(&self, key: &str) -> Result<bool, Self::Error>;
    async fn exists(&self, key: &str) -> Result<bool, Self::Error>;
}

pub struct MultiLevelCache<L1, L2> {
    l1: L1,  // local (fast)
    l2: L2,  // distributed (slow)
}

impl<L1: CacheBackend, L2: CacheBackend> MultiLevelCache<L1, L2> {
    pub async fn get(&self, key: &str) -> Result<Option<Vec<u8>>, CacheError> {
        // Try L1 first
        if let Some(value) = self.l1.get(key).await? {
            return Ok(Some(value));
        }
        // Fall back to L2
        if let Some(value) = self.l2.get(key).await? {
            // Populate L1
            self.l1.set(key, &value, None).await?;
            return Ok(Some(value));
        }
        Ok(None)
    }
}
